import hashlib
import os
import shutil
import logging
from pathlib import Path

log = logging.getLogger(__name__)
BUF_SIZE = 65536


def file_hash(path: str) -> str:
    sha256 = hashlib.sha256()
    with open(path, 'rb') as f:
        while chunk := f.read(BUF_SIZE):
            sha256.update(chunk)
    return sha256.hexdigest()


def find_duplicates(directory: str) -> dict[str, list[str]]:
    """Find duplicate files by content hash. Returns {hash: [paths]}."""
    hashes: dict[str, list[str]] = {}
    for root, _, files in os.walk(directory):
        for name in files:
            path = os.path.join(root, name)
            h = file_hash(path)
            hashes.setdefault(h, []).append(path)
    return {h: paths for h, paths in hashes.items() if len(paths) > 1}


def deduplicate(directory: str, quarantine_dir: str = 'quarantine') -> int:
    """Move duplicate files to quarantine. Keeps the oldest copy."""
    os.makedirs(quarantine_dir, exist_ok=True)
    duplicates = find_duplicates(directory)
    moved = 0
    for h, paths in duplicates.items():
        paths.sort(key=lambda p: os.path.getmtime(p))
        keep = paths[0]
        for dup in paths[1:]:
            dest = os.path.join(quarantine_dir, os.path.basename(dup))
            shutil.move(dup, dest)
            log.info('Moved duplicate %s -> %s (kept %s)', dup, dest, keep)
            moved += 1
    return moved
